import React, { useState } from 'react';
import { Product } from '../types';
import { ShoppingBag, Sparkles, Loader2, Check, Clock } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  onAddToCart: (product: Product, quantity: number) => void;
  onClick: (product: Product) => void;
  index?: number;
}

export const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart, onClick }) => {
  const [addState, setAddState] = useState<'idle' | 'loading' | 'success'>('idle');

  const stock = product.stock || 0;
  const isPreOrder = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;

  const handleAddToCart = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (addState !== 'idle') return;

    setAddState('loading');
    setTimeout(() => {
      onAddToCart(product, 1);
      setAddState('success');
      setTimeout(() => setAddState('idle'), 2000);
    }, 600);
  };

  const descriptionPreview = product.description 
    ? product.description.split('.')[0] + '.' 
    : '';

  return (
    <div className="group relative w-full flex flex-col items-center">
      <div onClick={() => onClick(product)} className="relative w-full aspect-[3/4] mx-auto max-w-sm transition-transform duration-500 hover:-translate-y-2 cursor-pointer">
        <div className="absolute top-4 -right-4 w-full h-full bg-brand-latte/20 rounded-[30px] -rotate-2 transition-transform duration-500 group-hover:rotate-0 group-hover:translate-x-2 group-hover:translate-y-2"></div>
        <div className="absolute -bottom-4 -left-4 w-full h-full bg-brand-pink/10 rounded-[30px] rotate-2 transition-transform duration-500 group-hover:rotate-0 group-hover:-translate-x-2 group-hover:-translate-y-2"></div>
        <div className="relative w-full h-full bg-white rounded-[24px] overflow-hidden shadow-2xl shadow-brand-latte/10 ring-1 ring-black/5 flex flex-col">
           <div className="w-full h-full overflow-hidden p-3 bg-white relative">
              <div className="w-full h-full overflow-hidden rounded-[16px] relative">
                {/* Removed grayscale and opacity logic to make product clear */}
                <img src={product.image} alt={product.name} loading="lazy" className="w-full h-full object-cover transition-transform duration-[1.5s] ease-in-out group-hover:scale-110" />

                {isPreOrder ? (
                  // Changed from full overlay to a distinct badge so product is visible
                  <div className="absolute top-3 right-3 z-10 pointer-events-none">
                    <div className="px-3 py-1.5 bg-white/95 backdrop-blur-sm border border-brand-gold/30 rounded-full shadow-sm">
                      <span className="font-serif text-[10px] text-brand-gold font-bold uppercase tracking-widest flex items-center gap-1.5">
                         <Clock size={12} /> Pre-order
                      </span>
                    </div>
                  </div>
                ) : (
                  <div className="absolute inset-0 bg-gradient-to-tr from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none"></div>
                )}
              </div>
           </div>

           <div className="absolute bottom-3 right-3 md:bottom-5 md:right-5 z-30 transform transition-all duration-300 translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100">
             <button onClick={handleAddToCart} disabled={addState !== 'idle'} className={`p-3 md:p-4 rounded-full shadow-lg transition-all active:scale-95 flex items-center justify-center group/btn ${addState === 'success' ? 'bg-brand-green text-white' : isPreOrder ? 'bg-brand-gold text-white hover:bg-brand-flamingo' : 'bg-brand-flamingo text-white md:hover:bg-brand-gold'}`} aria-label={isPreOrder ? "Pre-order now" : "Add to cart"}>
               {addState === 'loading' ? (<Loader2 size={18} className="animate-spin" />) : addState === 'success' ? (<Check size={18} strokeWidth={2} />) : (<ShoppingBag size={18} strokeWidth={1.5} className="md:group-hover/btn:animate-bounce" />)}
             </button>
           </div>
        </div>
      </div>
      <div className="mt-6 md:mt-10 text-center px-4 relative z-10 cursor-pointer" onClick={() => onClick(product)}>
        <h3 className="font-serif text-3xl text-gray-900 mb-2 group-hover:text-brand-flamingo transition-colors duration-300">{product.name}</h3>
        <p className="font-script text-2xl text-brand-gold mb-3 -mt-1 flex items-center justify-center gap-2">
          <Sparkles size={12} className="opacity-50" />
          {(!product.collection || product.collection === 'Blankets') ? 'Blanket Collection' : product.collection}
          <Sparkles size={12} className="opacity-50" />
        </p>
        <p className="font-serif text-gray-500 mb-4 max-w-[250px] mx-auto text-sm leading-relaxed line-clamp-2 opacity-80">{descriptionPreview}</p>
        <div className="flex flex-col items-center gap-2">
          <div className="inline-block px-5 py-1.5 rounded-full border border-brand-latte/30 bg-white shadow-sm group-hover:border-brand-flamingo/30 transition-colors">
            <span className="font-sans font-bold text-sm tracking-widest text-gray-900">RM {product.price}</span>
          </div>

          {/* Updated Text Description for Pre-orders */}
          {isPreOrder ? (
            <span className="font-serif italic text-xs text-brand-gold mt-1 font-medium">
              Sold Out • Pre-order ships in 2 weeks
            </span>
          ) : isLowStock && (
            <span className="font-serif italic text-xs text-brand-flamingo mt-1 animate-pulse">
              Only {stock} left
            </span>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { ArrowLeft, Minus, Plus, ShoppingBag, Truck, Info, Leaf, Loader2, Check, AlertCircle, Ruler, Share2, Clock } from 'lucide-react';
import { useParams, useNavigate } from 'react-router-dom';

interface ProductDetailsProps {
  products: Product[];
  onAddToCart: (product: Product, quantity: number) => void;
}

const getProductSlug = (name: string) => name.toLowerCase().replace(/\s+/g, '-').replace(/[^\w-]/g, '');

const AccordionItem: React.FC<{ title: string; children: React.ReactNode; isOpen: boolean; toggle: () => void }> = ({ title, children, isOpen, toggle }) => (
  <div className="border-b border-brand-latte/20">
    <button onClick={toggle} className="w-full py-4 flex items-center justify-between text-left group">
      <span className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 group-hover:text-brand-flamingo transition-colors">{title}</span>
      {isOpen ? <Minus size={14} className="text-brand-flamingo" /> : <Plus size={14} className="text-gray-400" />}
    </button>
    <div className={`overflow-hidden transition-all duration-500 ease-in-out ${isOpen ? 'max-h-96 opacity-100 mb-6' : 'max-h-0 opacity-0'}`}>
      <div className="font-sans text-sm text-gray-500 leading-relaxed font-light">
        {children}
      </div>
    </div>
  </div>
);

export const ProductDetails: React.FC<ProductDetailsProps> = ({ products, onAddToCart }) => {
  const { slug } = useParams<{ slug: string }>();
  const navigate = useNavigate();
  const [product, setProduct] = useState<Product | undefined>(undefined);
  const [loading, setLoading] = useState(true);
  const [activeImage, setActiveImage] = useState<string>('');

  const [openSection, setOpenSection] = useState<string>('material');
  const [quantity, setQuantity] = useState(1);
  const [addState, setAddState] = useState<'idle' | 'loading' | 'success'>('idle');
  const [shareStatus, setShareStatus] = useState<'idle' | 'copied'>('idle');

  useEffect(() => {
    if (products.length > 0 && slug) {
      let found = products.find(p => getProductSlug(p.name) === slug);
      if (!found) {
        found = products.find(p => p.id === slug);
      }
      setProduct(found);
      if (found) setActiveImage(found.image);
      setLoading(false);
    } else if (products.length === 0) {
      const timer = setTimeout(() => setLoading(false), 2000);
      return () => clearTimeout(timer);
    } else {
        setLoading(false);
    }
  }, [slug, products]);

  const toggleSection = (section: string) => {
    setOpenSection(openSection === section ? '' : section);
  };

  const handleAddToCart = () => {
    if (addState !== 'idle' || !product) return;
    setAddState('loading');
    setTimeout(() => {
      onAddToCart(product, quantity);
      setAddState('success');
      setTimeout(() => {
        setAddState('idle');
      }, 2000);
    }, 600);
  };

  const handleShare = async () => {
    if (!product) return;
    const shareData = {
      title: product.name,
      text: `Check out ${product.name} on Once Upon`,
      url: window.location.href,
    };
    if (navigator.share) {
      try { await navigator.share(shareData); } catch (err) { console.log('Share canceled or failed'); }
    } else {
      try {
        await navigator.clipboard.writeText(window.location.href);
        setShareStatus('copied');
        setTimeout(() => setShareStatus('idle'), 2000);
      } catch (err) { console.error('Failed to copy'); }
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center pt-24">
        <Loader2 className="animate-spin text-brand-latte" />
      </div>
    );
  }

  if (!product) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center pt-24 pb-12">
        <AlertCircle size={48} className="text-brand-latte mb-4 opacity-50" />
        <h2 className="font-serif text-2xl text-gray-900 mb-2">Product Not Found</h2>
        <p className="text-gray-500 mb-6">The item you are looking for does not exist.</p>
        <button onClick={() => navigate('/')} className="text-xs font-bold uppercase tracking-widest text-brand-flamingo hover:text-brand-gold">
          Return to Shop
        </button>
      </div>
    );
  }

  const galleryImages = [product.image, ...(product.additionalImages || [])];
  const stock = product.stock || 0;
  const isPreOrder = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;

  // If pre-order, quantity is effectively unlimited (or reasonable max), else capped by stock
  const maxQty = isPreOrder ? 100 : stock;

  return (
    <div className="min-h-screen bg-white animate-fade-in pt-24 pb-12">
      <div className="container mx-auto px-6 max-w-6xl">
        <button onClick={() => navigate('/')} className="flex items-center gap-2 text-gray-400 hover:text-brand-flamingo mb-8 transition-colors group">
          <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" />
          <span className="font-sans text-[10px] uppercase tracking-widest font-bold">Back to Shop</span>
        </button>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-24">
          <div className="flex flex-col gap-6">
            <div className="relative aspect-[3/4] bg-brand-grey/5 rounded-[2px] overflow-hidden group border border-brand-latte/10">
               {/* Removed grayscale here */}
               <img src={activeImage || product.image} alt={product.name} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" />
               {isPreOrder && (
                  // Removed full overlay, added distinct badge
                  <div className="absolute top-4 right-4 pointer-events-none">
                    <div className="px-6 py-3 bg-white/95 border border-brand-gold/30 rounded-full shadow-sm">
                      <span className="font-serif text-xl text-brand-gold font-bold uppercase tracking-widest flex items-center gap-2">
                        <Clock size={20} /> Pre-order
                      </span>
                    </div>
                  </div>
               )}
            </div>
            {galleryImages.length > 1 && (
              <div className="grid grid-cols-4 gap-4">
                 {galleryImages.map((img, i) => (
                   // Removed grayscale here as well
                   <div key={i} onClick={() => setActiveImage(img)} className={`aspect-square bg-brand-grey/10 cursor-pointer overflow-hidden rounded-[2px] border transition-all duration-300 ${activeImage === img ? 'border-brand-flamingo ring-1 ring-brand-flamingo/50' : 'border-transparent hover:border-brand-latte'}`}>
                     <img src={img} className={`w-full h-full object-cover transition-opacity duration-300 ${activeImage === img ? 'opacity-100' : 'opacity-70 hover:opacity-100'}`} alt={`${product.name} view ${i + 1}`} />
                   </div>
                 ))}
              </div>
            )}
          </div>

          <div className="flex flex-col pt-4">
            <div className="flex justify-between items-start gap-4 mb-2">
               <h1 className="font-serif text-3xl md:text-4xl text-gray-900 leading-tight">{product.name}</h1>
               <button onClick={handleShare} className="mt-1 p-2 text-brand-latte hover:text-brand-flamingo hover:bg-brand-flamingo/5 rounded-full transition-all duration-300 relative group flex-shrink-0" aria-label="Share product">
                  <span className={`absolute right-full mr-3 top-1/2 -translate-y-1/2 text-[9px] font-bold uppercase tracking-widest text-brand-green whitespace-nowrap pointer-events-none transition-all duration-300 ${shareStatus === 'copied' ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-2'}`}>Link Copied</span>
                  {shareStatus === 'copied' ? (<Check size={20} className="text-brand-green" strokeWidth={1.5} />) : (<Share2 size={20} strokeWidth={1.5} />)}
               </button>
            </div>
