import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { ArrowLeft, Minus, Plus, ShoppingBag, Truck, Info, Leaf, Loader2, Check, AlertCircle, Ruler, Share2, Clock } from 'lucide-react';
import { useParams, useNavigate } from 'react-router-dom';

interface ProductDetailsProps {
  products: Product[];
  onAddToCart: (product: Product, quantity: number) => void;
}

const getProductSlug = (name: string) => name.toLowerCase().replace(/\s+/g, '-').replace(/[^\w-]/g, '');

const AccordionItem: React.FC<{ title: string; children: React.ReactNode; isOpen: boolean; toggle: () => void }> = ({ title, children, isOpen, toggle }) => (
  <div className="border-b border-brand-latte/20">
    <button onClick={toggle} className="w-full py-4 flex items-center justify-between text-left group">
      <span className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 group-hover:text-brand-flamingo transition-colors">{title}</span>
      {isOpen ? <Minus size={14} className="text-brand-flamingo" /> : <Plus size={14} className="text-gray-400" />}
    </button>
    <div className={`overflow-hidden transition-all duration-500 ease-in-out ${isOpen ? 'max-h-96 opacity-100 mb-6' : 'max-h-0 opacity-0'}`}>
      <div className="font-sans text-sm text-gray-500 leading-relaxed font-light">
        {children}
      </div>
    </div>
  </div>
);

export const ProductDetails: React.FC<ProductDetailsProps> = ({ products, onAddToCart }) => {
  const { slug } = useParams<{ slug: string }>();
  const navigate = useNavigate();
  const [product, setProduct] = useState<Product | undefined>(undefined);
  const [loading, setLoading] = useState(true);
  const [activeImage, setActiveImage] = useState<string>('');

  const [openSection, setOpenSection] = useState<string>('material');
  const [quantity, setQuantity] = useState(1);
  const [addState, setAddState] = useState<'idle' | 'loading' | 'success'>('idle');
  const [shareStatus, setShareStatus] = useState<'idle' | 'copied'>('idle');

  useEffect(() => {
    if (products.length > 0 && slug) {
      let found = products.find(p => getProductSlug(p.name) === slug);
      if (!found) {
        found = products.find(p => p.id === slug);
      }
      setProduct(found);
      if (found) setActiveImage(found.image);
      setLoading(false);
    } else if (products.length === 0) {
      const timer = setTimeout(() => setLoading(false), 2000);
      return () => clearTimeout(timer);
    } else {
        setLoading(false);
    }
  }, [slug, products]);

  const toggleSection = (section: string) => {
    setOpenSection(openSection === section ? '' : section);
  };

  const handleAddToCart = () => {
    if (addState !== 'idle' || !product) return;
    setAddState('loading');
    setTimeout(() => {
      onAddToCart(product, quantity);
      setAddState('success');
      setTimeout(() => {
        setAddState('idle');
      }, 2000);
    }, 600);
  };

  const handleShare = async () => {
    if (!product) return;
    const shareData = {
      title: product.name,
      text: `Check out ${product.name} on Once Upon`,
      url: window.location.href,
    };
    if (navigator.share) {
      try { await navigator.share(shareData); } catch (err) { console.log('Share canceled or failed'); }
    } else {
      try {
        await navigator.clipboard.writeText(window.location.href);
        setShareStatus('copied');
        setTimeout(() => setShareStatus('idle'), 2000);
      } catch (err) { console.error('Failed to copy'); }
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center pt-24">
        <Loader2 className="animate-spin text-brand-latte" />
      </div>
    );
  }

  if (!product) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center pt-24 pb-12">
        <AlertCircle size={48} className="text-brand-latte mb-4 opacity-50" />
        <h2 className="font-serif text-2xl text-gray-900 mb-2">Product Not Found</h2>
        <p className="text-gray-500 mb-6">The item you are looking for does not exist.</p>
        <button onClick={() => navigate('/')} className="text-xs font-bold uppercase tracking-widest text-brand-flamingo hover:text-brand-gold">
          Return to Shop
        </button>
      </div>
    );
  }

  const galleryImages = [product.image, ...(product.additionalImages || [])];
  const stock = product.stock || 0;
  const isPreOrder = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;

  // If pre-order, quantity is effectively unlimited (or reasonable max), else capped by stock
  const maxQty = isPreOrder ? 100 : stock;

  return (
    <div className="min-h-screen bg-white animate-fade-in pt-24 pb-12">
      <div className="container mx-auto px-6 max-w-6xl">
        <button onClick={() => navigate('/')} className="flex items-center gap-2 text-gray-400 hover:text-brand-flamingo mb-8 transition-colors group">
          <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" />
          <span className="font-sans text-[10px] uppercase tracking-widest font-bold">Back to Shop</span>
        </button>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-24">
          <div className="flex flex-col gap-6">
            <div className="relative aspect-[3/4] bg-brand-grey/5 rounded-[2px] overflow-hidden group border border-brand-latte/10">
               {/* Removed grayscale here */}
               <img src={activeImage || product.image} alt={product.name} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" />
               {isPreOrder && (
                  // Made smaller on mobile (px-3 py-1.5 text-xs) and larger on desktop (md:px-6 md:py-3 md:text-xl)
                  <div className="absolute top-4 right-4 pointer-events-none">
                    <div className="px-3 py-1.5 md:px-6 md:py-3 bg-white/95 border border-brand-gold/30 rounded-full shadow-sm">
                      <span className="font-serif text-xs md:text-xl text-brand-gold font-bold uppercase tracking-widest flex items-center gap-2">
                        <Clock size={14} className="md:w-5 md:h-5" /> Pre-order
                      </span>
                    </div>
                  </div>
               )}
            </div>
            {galleryImages.length > 1 && (
              <div className="grid grid-cols-4 gap-4">
                 {galleryImages.map((img, i) => (
                   // Removed grayscale here as well
                   <div key={i} onClick={() => setActiveImage(img)} className={`aspect-square bg-brand-grey/10 cursor-pointer overflow-hidden rounded-[2px] border transition-all duration-300 ${activeImage === img ? 'border-brand-flamingo ring-1 ring-brand-flamingo/50' : 'border-transparent hover:border-brand-latte'}`}>
                     <img src={img} className={`w-full h-full object-cover transition-opacity duration-300 ${activeImage === img ? 'opacity-100' : 'opacity-70 hover:opacity-100'}`} alt={`${product.name} view ${i + 1}`} />
                   </div>
                 ))}
              </div>
            )}
          </div>

          <div className="flex flex-col pt-4">
            <div className="flex justify-between items-start gap-4 mb-2">
               <h1 className="font-serif text-3xl md:text-4xl text-gray-900 leading-tight">{product.name}</h1>
               <button onClick={handleShare} className="mt-1 p-2 text-brand-latte hover:text-brand-flamingo hover:bg-brand-flamingo/5 rounded-full transition-all duration-300 relative group flex-shrink-0" aria-label="Share product">
                  <span className={`absolute right-full mr-3 top-1/2 -translate-y-1/2 text-[9px] font-bold uppercase tracking-widest text-brand-green whitespace-nowrap pointer-events-none transition-all duration-300 ${shareStatus === 'copied' ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-2'}`}>Link Copied</span>
                  {shareStatus === 'copied' ? (<Check size={20} className="text-brand-green" strokeWidth={1.5} />) : (<Share2 size={20} strokeWidth={1.5} />)}
               </button>
            </div>
            <div className="flex items-center gap-4 mb-8">
              <span className="font-serif text-2xl text-gray-900">RM {product.price}</span>
              <div className="h-4 w-[1px] bg-gray-200"></div>
              <span className="font-script text-xl text-brand-gold">{(!product.collection || product.collection === 'Blankets') ? 'Blanket Collection' : product.collection}</span>
            </div>
            <p className="font-serif italic text-gray-600 text-base leading-relaxed mb-8 border-l-2 border-brand-flamingo pl-6">"{product.description}"</p>

            <div className="flex flex-col gap-4 mb-12">
               <div className="flex flex-col sm:flex-row gap-4">
                 <div className="flex items-center border border-brand-latte/30 rounded-full h-12 w-full sm:w-32 px-4 justify-between bg-white">
                   <button onClick={() => setQuantity(Math.max(1, quantity - 1))} className="text-gray-400 hover:text-brand-flamingo disabled:opacity-30"><Minus size={14}/></button>
                   <span className="font-sans font-bold text-sm text-gray-900">{quantity}</span>
                   <button onClick={() => setQuantity(Math.min(maxQty, quantity + 1))} className="text-gray-400 hover:text-brand-flamingo disabled:opacity-30" disabled={quantity >= maxQty}><Plus size={14}/></button>
                 </div>
                 <button onClick={handleAddToCart} disabled={addState !== 'idle'} className={`w-full sm:flex-1 h-12 rounded-full flex items-center justify-center gap-3 transition-all duration-300 font-sans text-[11px] uppercase tracking-[0.2em] font-bold shadow-lg ${addState === 'success' ? 'bg-brand-green text-white hover:bg-brand-green/90 shadow-brand-green/20' : isPreOrder ? 'bg-brand-gold text-white hover:bg-brand-flamingo shadow-brand-gold/20' : 'bg-brand-flamingo text-white hover:bg-brand-gold shadow-brand-flamingo/20'}`}>
                   {addState === 'loading' ? (<Loader2 size={16} className="animate-spin" />) : addState === 'success' ? (<><Check size={16} />Added</>) : isPreOrder ? (<><Clock size={16} strokeWidth={1.5} />Pre-order Item</>) : (<><ShoppingBag size={16} strokeWidth={1.5} />Add to Bag</>)}
                 </button>
               </div>

               {isPreOrder ? (
                 <div className="flex items-start gap-3 text-brand-gold bg-brand-gold/5 p-4 rounded-[2px] border border-brand-gold/10">
                   <Clock size={18} className="mt-0.5 flex-shrink-0" />
                   <div>
                     <p className="font-bold text-xs uppercase tracking-wider mb-1">Item Sold Out</p>
                     <p className="font-serif italic text-sm text-gray-600">This item is available for <strong>pre-order</strong>. It is currently crafting and will ship in approximately <strong>2 weeks</strong>.</p>
                   </div>
                 </div>
               ) : isLowStock && (
                 <div className="flex items-center gap-2 text-brand-flamingo animate-pulse">
                   <AlertCircle size={14} />
                   <span className="font-serif italic text-sm">Hurry! Only {stock} left in stock.</span>
                 </div>
               )}
            </div>

            <div className="mt-auto">
              <AccordionItem title="Material & Composition" isOpen={openSection === 'material'} toggle={() => toggleSection('material')}>
                <div className="flex items-start gap-3"><Leaf size={16} className="text-brand-latte mt-1 flex-shrink-0" /><p>{product.material || 'Premium ethically sourced fibers.'}</p></div>
              </AccordionItem>
              <AccordionItem title="Dimensions" isOpen={openSection === 'size'} toggle={() => toggleSection('size')}>
                <div className="flex items-start gap-3"><Ruler size={16} className="text-brand-latte mt-1 flex-shrink-0" /><p>{product.size || 'One size fits most.'}</p></div>
              </AccordionItem>
              <AccordionItem title="Care Instructions" isOpen={openSection === 'care'} toggle={() => toggleSection('care')}>
                <div className="flex items-start gap-3"><Info size={16} className="text-brand-latte mt-1 flex-shrink-0" /><p>{product.care || 'Gentle hand wash recommended to preserve the softness of the fibers.'}</p></div>
              </AccordionItem>
              <AccordionItem title="Shipping & Returns" isOpen={openSection === 'shipping'} toggle={() => toggleSection('shipping')}>
                 <div className="flex items-start gap-3"><Truck size={16} className="text-brand-latte mt-1 flex-shrink-0" /><div className="flex flex-col gap-3"><p>Delivery to West Malaysia is available at a flat rate of RM 8.00. For larger orders containing three (3) or more items, a standard shipping fee of RM 10.00 applies. </p><p>Shipping to East Malaysia (Sabah & Sarawak) is charged at RM 12.00.</p><p className="italic text-brand-gold">Please kindly note that all sales are final. We are unable to accept returns or exchanges.</p></div></div>
              </AccordionItem>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { CartItem } from '../types';
import { Lock, CheckCircle, ArrowLeft, Loader2, CreditCard, AlertTriangle, Tag, X, Gift, PenTool, Sparkles, ChevronRight, Mail, Phone, MapPin, Clock } from 'lucide-react';
import { createOrderInDb } from '../firebase';
import { useNavigate } from 'react-router-dom';

interface CheckoutViewProps {
  cart: CartItem[];
  onOrderSuccess: () => void;
}

const API_URL = '/api/chip/purchases/';

export const CheckoutView: React.FC<CheckoutViewProps> = ({ cart, onOrderSuccess }) => {
  const navigate = useNavigate();

  // --- STATE ---
  const [step, setStep] = useState<1 | 2 | 3>(1); // 1: Contact, 2: Shipping, 3: Finalize

  // Cart & Totals
  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  // Packaging Logic: 1 set for every 1 item
  const packagingCount = totalItems;

  // Form Data
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');

  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [address, setAddress] = useState('');
  const [postcode, setPostcode] = useState('');
  const [city, setCity] = useState('');
  const [region, setRegion] = useState<'west' | 'east'>('west');

  const [isGift, setIsGift] = useState(false);
  const [giftTo, setGiftTo] = useState('');
  const [giftFrom, setGiftFrom] = useState('');

  // Voucher
  const [voucherCode, setVoucherCode] = useState('');
  const [isFreeShipping, setIsFreeShipping] = useState(false);
  const [isTestDiscount, setIsTestDiscount] = useState(false);
  const [voucherMessage, setVoucherMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  // Payment Status
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState('');

  // --- LOGIC ---

  const calculateShipping = () => {
    if (isTestDiscount) return 0;
    if (isFreeShipping) return 0;
    if (region === 'east') return 12;
    return totalItems >= 3 ? 10 : 8;
  };

  const shippingCost = calculateShipping();

  // Calculate total and potential discount
  let total = subtotal + shippingCost;
  let discountAmount = 0;

  if (isTestDiscount) {
    // Force total to 1
    discountAmount = total - 1;
    total = 1;
  }

  const getPaymentConfig = () => {
    const env = (import.meta as any).env;
    return {
      brandId: env.VITE_CHIP_ID || env.CHIP_ID,
      apiKey: env.VITE_CHIP_API || env.CHIP_API
    };
  };

  // --- HANDLERS ---

  const handleApplyVoucher = (e: React.MouseEvent) => {
    e.preventDefault();
    setVoucherMessage(null);
    const code = voucherCode.trim().toUpperCase();
    if (!code) return;

    if (code === 'SHIPFREE88') {
      setIsFreeShipping(true);
      setIsTestDiscount(false);
      setVoucherMessage({ type: 'success', text: 'Free shipping applied!' });
    } else if (code === 'TESTRM1') {
      setIsTestDiscount(true);
      setIsFreeShipping(false);
      setVoucherMessage({ type: 'success', text: 'Test discount applied! Total is RM 1.' });
    } else {
      setIsFreeShipping(false);
      setIsTestDiscount(false);
      setVoucherMessage({ type: 'error', text: 'Invalid voucher code.' });
    }
  };

  const handleRemoveVoucher = () => {
    setVoucherCode('');
    setIsFreeShipping(false);
    setIsTestDiscount(false);
    setVoucherMessage(null);
  };

  const handleNextStep = (e: React.FormEvent) => {
    e.preventDefault();
    if (step === 1) {
      if (email && phone) setStep(2);
    } else if (step === 2) {
      if (firstName && lastName && address && postcode && city) setStep(3);
    } else if (step === 3) {
      handleSubmit();
    }
  };

  const handleSubmit = async () => {
    setIsProcessing(true);
    setError('');

    const { brandId, apiKey } = getPaymentConfig();
    if (!brandId || !apiKey) {
      setError("Payment Configuration Missing. Please contact support.");
      setIsProcessing(false);
      return;
    }

    try {
      // 1. Create Order in Database
      // Note: This function now checks STOCK and deducts it transactionally.
      // If stock is unavailable, it will throw an error.
      const orderRef = await createOrderInDb({
        customerName: `${firstName} ${lastName}`,
        customerEmail: email,
        customerPhone: phone,
        items: cart,
        total: total,
        status: 'pending',
        date: new Date().toISOString(),
        shippingAddress: `${address}, ${postcode} ${city}, ${region === 'east' ? 'East Malaysia' : 'West Malaysia'}`,
        isGift: isGift,
        // Fix: Firestore crashes if fields are undefined. We default to empty strings.
        giftTo: isGift ? (giftTo || '') : '',
        giftFrom: isGift ? (giftFrom || '') : ''
      });

      // 2. Chip Payload
      const productsPayload = [
        ...cart.map(item => ({
          name: item.name.substring(0, 256),
          quantity: item.quantity,
          price: Math.round(item.price * 100)
        })),
        {
          name: (isFreeShipping || isTestDiscount) ? "Shipping Fee (Waived)" : "Shipping Fee",
          quantity: 1,
          price: Math.round(shippingCost * 100)
        }
      ];

      // Add negative line item for test discount
      if (isTestDiscount) {
        productsPayload.push({
            name: "Voucher Discount (TESTRM1)",
            quantity: 1,
            price: -Math.round(discountAmount * 100)
        });
      }

      const payload = {
        brand_id: brandId,
        client: {
          email: email,
          phone: phone, 
          full_name: `${firstName} ${lastName}`.substring(0, 30),
        },
        purchase: {
          currency: 'MYR',
          products: productsPayload
        },
        reference: orderRef.id,
        // Remove /# from the redirect URLs to support BrowserRouter
        success_redirect: `${window.location.origin}/#/payment/callback?result=success&order=${orderRef.id}`,
        failure_redirect: `${window.location.origin}/#/payment/callback?result=failed&order=${orderRef.id}`,
        cancel_redirect: `${window.location.origin}/#/payment/callback?result=cancelled&order=${orderRef.id}`,
      };

      // 3. Call API
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
        body: JSON.stringify(payload)
      });

      let data;
      try { data = await response.json(); } catch (e) { throw new Error("Payment gateway response invalid."); }

      if (!response.ok) {
        throw new Error(data.message || "Payment initialization failed");
      }

      onOrderSuccess(); 
      if (data.checkout_url) window.location.href = data.checkout_url;
      else throw new Error("No checkout URL returned.");

    } catch (err: any) {
      console.error("Payment Error:", err);
      // Specific handling for out of stock errors coming from Firebase
      if (err.message.includes('out of stock')) {
         setError(err.message);
      } else {
         setError(err.message || "Failed to initiate payment. Please try again.");
      }
      setIsProcessing(false);
    }
  };

  // --- RENDER HELPERS ---

  const StepIndicator = () => (
    <div className="flex items-center gap-4 mb-12">
      <div className={`flex items-center gap-2 ${step >= 1 ? 'text-gray-900' : 'text-gray-300'}`}>
        <div className={`w-6 h-6 rounded-full flex items-center justify-center font-serif text-xs border ${step >= 1 ? 'border-gray-900 bg-gray-900 text-white' : 'border-gray-300'}`}>1</div>
        <span className="text-[10px] font-bold uppercase tracking-widest hidden md:inline">Contact</span>
      </div>
      <div className={`h-[1px] w-8 ${step >= 2 ? 'bg-gray-900' : 'bg-gray-200'}`}></div>
      <div className={`flex items-center gap-2 ${step >= 2 ? 'text-gray-900' : 'text-gray-300'}`}>
        <div className={`w-6 h-6 rounded-full flex items-center justify-center font-serif text-xs border ${step >= 2 ? 'border-gray-900 bg-gray-900 text-white' : 'border-gray-300'}`}>2</div>
        <span className="text-[10px] font-bold uppercase tracking-widest hidden md:inline">Shipping</span>
      </div>
      <div className={`h-[1px] w-8 ${step >= 3 ? 'bg-gray-900' : 'bg-gray-200'}`}></div>
      <div className={`flex items-center gap-2 ${step >= 3 ? 'text-gray-900' : 'text-gray-300'}`}>
        <div className={`w-6 h-6 rounded-full flex items-center justify-center font-serif text-xs border ${step >= 3 ? 'border-gray-900 bg-gray-900 text-white' : 'border-gray-300'}`}>3</div>
        <span className="text-[10px] font-bold uppercase tracking-widest hidden md:inline">Finalize</span>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-white animate-fade-in flex flex-col lg:flex-row">

      {/* LEFT COLUMN: WIZARD FORM */}
      <div className="w-full lg:w-[58%] px-6 lg:px-24 pt-12 lg:pt-24 pb-12 border-r border-brand-latte/10 flex flex-col">
        <div className="max-w-xl mx-auto lg:mx-0 w-full flex-1 flex flex-col">

          <div className="flex justify-between items-center mb-10">
             <button onClick={() => step === 1 ? navigate('/cart') : setStep(prev => (prev - 1) as any)} className="flex items-center gap-2 text-gray-400 hover:text-brand-flamingo transition-colors text-xs font-bold uppercase tracking-widest group">
               <ArrowLeft size={14} className="group-hover:-translate-x-1 transition-transform" /> 
               {step === 1 ? 'Back to Bag' : 'Go Back'}
             </button>
          </div>

          <StepIndicator />

          <form onSubmit={handleNextStep} className="flex-1 flex flex-col relative">

            {/* --- STEP 1: CONTACT --- */}
            {step === 1 && (
              <div className="animate-fade-in space-y-8">
                 <div>
                   <h1 className="font-serif text-3xl text-gray-900 mb-2">Contact Details</h1>
                   <p className="font-script text-xl text-brand-gold">Where shall we send your receipt?</p>
                 </div>

                 <div className="space-y-6">
                    <div className="relative group">
                      <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-2 group-focus-within:text-brand-flamingo transition-colors">Email Address</label>
                      <input 
                        type="email" 
                        required
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        placeholder="hello@example.com"
                        className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors pl-8"
                      />
                      <Mail size={16} className="absolute left-0 bottom-3.5 text-gray-300 group-focus-within:text-brand-flamingo transition-colors" />
                    </div>

                    <div className="relative group">
                      <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-2 group-focus-within:text-brand-flamingo transition-colors">Phone Number</label>
                      <input 
                        type="tel" 
                        required
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        placeholder="+60..."
                        className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors pl-8"
                      />
                       <Phone size={16} className="absolute left-0 bottom-3.5 text-gray-300 group-focus-within:text-brand-flamingo transition-colors" />
                    </div>

                    <div className="bg-brand-grey/5 p-4 rounded-[2px] border border-brand-latte/10 flex items-start gap-3">
                       <CheckCircle size={16} className="text-brand-green mt-0.5" />
                       <p className="text-xs text-gray-500 font-light leading-relaxed">
                         We'll only use these details to send your order confirmation and shipping updates.
                       </p>
                    </div>
                 </div>
              </div>
            )}

            {/* --- STEP 2: SHIPPING --- */}
            {step === 2 && (
              <div className="animate-fade-in space-y-8">
                 <div>
                   <h1 className="font-serif text-3xl text-gray-900 mb-2">Shipping Address</h1>
                   <p className="font-script text-xl text-brand-gold">Where is this package traveling to?</p>
                 </div>

                 <div className="space-y-6">
                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <input 
                          type="text" placeholder="First Name" required 
                          value={firstName} onChange={e => setFirstName(e.target.value)}
                          className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                        />
                      </div>
                      <div>
                        <input 
                          type="text" placeholder="Last Name" required 
                          value={lastName} onChange={e => setLastName(e.target.value)}
                          className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                        />
                      </div>
                    </div>

                    <div className="relative">
                      <input 
                        type="text" placeholder="Street Address" required 
                        value={address} onChange={e => setAddress(e.target.value)}
                        className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors pl-6" 
                      />
                      <MapPin size={16} className="absolute left-0 top-3.5 text-gray-300" />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                       <input 
                        type="text" placeholder="Postcode" required 
                        value={postcode} onChange={e => setPostcode(e.target.value)}
                        className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                       />
                       <input 
                        type="text" placeholder="City" required 
                        value={city} onChange={e => setCity(e.target.value)}
                        className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                       />
                    </div>

                    <div>
                      <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-2">Region</label>
                      <div className="relative">
                        <select 
                          value={region}
                          onChange={(e) => setRegion(e.target.value as 'west' | 'east')}
                          className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 transition-colors appearance-none cursor-pointer"
                        >
                          <option value="west">West Malaysia (Peninsular)</option>
                          <option value="east">East Malaysia (Sabah & Sarawak)</option>
                        </select>
                        <div className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none opacity-50">
                          <svg width="10" height="6" viewBox="0 0 10 6" fill="currentColor"><path d="M5 6L0 0H10L5 6Z" /></svg>
                        </div>
                      </div>
                    </div>
                 </div>
              </div>
            )}

            {/* --- STEP 3: FINALIZE --- */}
            {step === 3 && (
              <div className="animate-fade-in space-y-8">
                 <div>
                   <h1 className="font-serif text-3xl text-gray-900 mb-2">Finishing Touches</h1>
                   <p className="font-script text-xl text-brand-gold">Make it special.</p>
                 </div>

                 {/* Gift Section */}
                 <div className="bg-brand-grey/5 p-6 rounded-[2px] border border-brand-latte/10">
                    <div className="flex items-center gap-3 mb-4">
                       <input 
                          id="isGift"
                          type="checkbox"
                          checked={isGift}
                          onChange={(e) => setIsGift(e.target.checked)}
                          className="w-4 h-4 text-brand-flamingo rounded border-gray-300 focus:ring-brand-flamingo accent-brand-flamingo"
                       />
                       <label htmlFor="isGift" className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 cursor-pointer select-none">
                         Would you like us to write on the card? (Optional)
                       </label>
                    </div>

                    <div className={`grid grid-cols-2 gap-6 transition-all duration-500 overflow-hidden ${isGift ? 'max-h-40 opacity-100 mt-4' : 'max-h-0 opacity-0'}`}>
                      <div className="col-span-1">
                         <input 
                           type="text" 
                           placeholder="To (Name) - Optional"
                           value={giftTo}
                           onChange={(e) => setGiftTo(e.target.value)}
                           className="w-full bg-white border-b border-brand-latte/40 px-3 py-2 font-serif text-gray-800 focus:outline-none focus:border-brand-flamingo placeholder:text-gray-400 text-sm"
                         />
                      </div>
                      <div className="col-span-1">
                         <input 
                           type="text" 
                           placeholder="From (Name) - Optional"
                           value={giftFrom}
                           onChange={(e) => setGiftFrom(e.target.value)}
                           className="w-full bg-white border-b border-brand-latte/40 px-3 py-2 font-serif text-gray-800 focus:outline-none focus:border-brand-flamingo placeholder:text-gray-400 text-sm"
                         />
                      </div>
                    </div>
                 </div>

                 {/* Voucher Section */}
                 <div>
                    <h3 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-4 flex items-center gap-2">
                       <Tag size={14} className="text-gray-400" /> Have a voucher?
                    </h3>
                    <div className="flex gap-2 relative">
                       <input 
                          type="text" 
                          placeholder="Enter code" 
                          value={voucherCode}
                          onChange={(e) => setVoucherCode(e.target.value)}
                          disabled={isFreeShipping || isTestDiscount}
                          className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors disabled:opacity-50" 
                        />
                        {(isFreeShipping || isTestDiscount) ? (
                          <button type="button" onClick={handleRemoveVoucher} className="text-gray-400 hover:text-red-400 px-4 border-b border-brand-latte/40"><X size={18} /></button>
                        ) : (
                          <button type="button" onClick={handleApplyVoucher} className="text-[10px] font-bold uppercase tracking-widest hover:text-brand-flamingo transition-colors px-2 border-b border-brand-latte/40">Apply</button>
                        )}
                    </div>
                    {voucherMessage && (
                        <p className={`text-xs mt-2 flex items-center gap-1 ${voucherMessage.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>
                          {voucherMessage.type === 'success' ? <CheckCircle size={12} /> : <AlertTriangle size={12} />}
                          {voucherMessage.text}
                        </p>
                    )}
                 </div>

                 {/* Error Display */}
                 {error && (
                    <div className="bg-red-50 p-4 rounded border border-red-100 flex items-start gap-3">
                      <AlertTriangle className="text-red-500 flex-shrink-0 mt-0.5" size={16} />
                      <div className="flex-1">
                        <p className="text-red-600 text-sm font-bold mb-1">Could Not Process Order</p>
                        <p className="text-red-500 text-xs">{error}</p>
                      </div>
                    </div>
                  )}
              </div>
            )}

            {/* --- ACTION BUTTONS --- */}
            <div className="mt-12 pt-6 border-t border-brand-latte/10">
               <button 
                  type="submit"
                  disabled={isProcessing}
                  className="w-full bg-brand-flamingo text-white h-14 rounded-full flex items-center justify-center gap-3 hover:bg-brand-gold transition-colors font-sans text-[11px] uppercase tracking-[0.2em] font-bold shadow-lg shadow-brand-flamingo/20 disabled:opacity-70 disabled:cursor-wait group"
               >
                  {isProcessing ? (
                    <>
                      <Loader2 size={16} className="animate-spin" /> {step === 3 ? 'Processing...' : 'Loading...'}
                    </>
                  ) : step === 3 ? (
                    `Pay RM ${total}`
                  ) : (
                    <>
                      Next Step <ChevronRight size={16} className="group-hover:translate-x-1 transition-transform" />
                    </>
                  )}
               </button>
            </div>

          </form>
        </div>
      </div>

      {/* RIGHT COLUMN: SUMMARY */}
      <div className="w-full lg:w-[42%] bg-brand-grey/5 px-6 lg:px-16 pt-12 lg:pt-24 pb-12 lg:min-h-screen border-l border-brand-latte/10">
        <div className="max-w-md mx-auto lg:mx-0 sticky top-24">
          <h2 className="font-serif text-2xl text-gray-900 mb-8">In Your Bag</h2>

          <div className="space-y-6 mb-8 max-h-[40vh] overflow-y-auto hide-scrollbar pr-2">
            {cart.map(item => (
              <div key={item.id} className="flex gap-4 items-start">
                 <div className="w-14 h-18 bg-white border border-brand-latte/20 relative rounded-[2px] overflow-hidden flex-shrink-0">
                    <img src={item.image} className={`w-full h-full object-cover ${item.isPreOrder ? 'grayscale-[20%]' : ''}`} />
                    <span className="absolute -top-0 -right-0 w-4 h-4 bg-brand-latte/90 text-white text-[9px] font-bold flex items-center justify-center rounded-bl-sm">
                      {item.quantity}
                    </span>
                 </div>
                 <div className="flex-1 min-w-0">
                   <h4 className="font-serif text-gray-900 text-sm truncate">{item.name}</h4>
                   <p className="text-[10px] text-gray-500 font-sans mt-0.5 uppercase tracking-wide">RM {item.price}</p>
                   {item.isPreOrder && (
                      <p className="text-[9px] text-brand-gold font-bold uppercase tracking-wide mt-1 flex items-center gap-1">
                        <Clock size={10} /> Ships in 2 weeks
                      </p>
                   )}
                 </div>
                 <div className="font-sans text-sm font-bold text-gray-900">
                   RM {item.price * item.quantity}
                 </div>
              </div>
            ))}
          </div>

          <div className="bg-white border border-brand-latte/20 p-5 rounded-[2px] mb-8">
            <h4 className="font-sans text-[10px] font-bold uppercase tracking-widest text-brand-gold mb-3 flex items-center gap-2">
              <Sparkles size={12} /> The Unboxing Experience
            </h4>
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                      <div className="w-7 h-7 rounded-full bg-brand-grey/10 flex items-center justify-center text-gray-400">
                          <Gift size={12} />
                      </div>
                      <p className="font-serif text-sm text-gray-900">Signature Keepsake Box</p>
                  </div>
                  <span className="font-serif text-sm text-brand-gold italic">x {packagingCount}</span>
              </div>
              <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                      <div className="w-7 h-7 rounded-full bg-brand-grey/10 flex items-center justify-center text-gray-400">
                          <PenTool size={12} />
                      </div>
                      <p className="font-serif text-sm text-gray-900">Gift Card</p>
                  </div>
                  <span className="font-serif text-sm text-brand-gold italic">x {packagingCount}</span>
              </div>
            </div>
          </div>

          <div className="border-t border-brand-latte/20 pt-6 space-y-3">
             <div className="flex justify-between text-sm font-sans text-gray-600">
                <span>Subtotal</span>
                <span>RM {subtotal}</span>
             </div>
             <div className="flex justify-between text-sm font-sans text-gray-600 items-center">
                <span>Shipping</span>
                {step < 2 ? (
                  <span className="text-xs italic text-gray-400">Calculated next step</span>
                ) : (isFreeShipping || isTestDiscount) ? (
                  <span className="text-brand-green font-bold text-xs uppercase tracking-wider flex items-center gap-1"><Tag size={10} /> Free</span>
                ) : (
                  <span>RM {shippingCost}</span>
                )}
             </div>
             {isTestDiscount && (
                 <div className="flex justify-between text-sm font-sans text-brand-flamingo font-bold">
                    <span>Discount (TESTRM1)</span>
                    <span>- RM {discountAmount.toFixed(2)}</span>
                 </div>
             )}
          </div>

          <div className="border-t border-brand-latte/20 pt-6 mt-6">
             <div className="flex justify-between items-end">
                <span className="font-serif text-xl text-gray-900">Total</span>
                <span className="font-serif text-3xl text-gray-900">RM {step < 2 ? subtotal : total}</span>
             </div>
          </div>

          <div className="mt-8 flex items-center gap-3 justify-center text-brand-gold opacity-60">
             <Lock size={12} />
             <span className="text-[10px] uppercase tracking-widest font-bold">Secure Payment via CHIP</span>
          </div>

        </div>
      </div>

    </div>
  );
};
